SELECT client_id, AVG(current_size) AS average_db_size
FROM databases
GROUP BY client_id;

SELECT db_name
FROM databases
WHERE current_size = (
  SELECT MAX(current_size)
  FROM databases
);

SELECT db_id, MAX(current_worker_threads) AS max_threads
FROM databases
GROUP BY db_id;

SELECT COUNT(DISTINCT db_id) AS high_cpu_databases_count
FROM usage_logs
WHERE cpu_usage = 'High';
